describe('notification ordering', () => {
  it('should deliver notifications in the order they were emitted', async () => {
    // Create an adapter with artificial delay to expose ordering issues.
    // The first send takes longer than the second — without ordering guarantees,
    // the second notification would be delivered first.
    let sendCount = 0;
    const deliveryOrder: string[] = [];

    const slowAdapter: import('../../src/adapters/notification.adapter.js').NotificationAdapter = {
      channel: 'email' as const,
      async send(payload) {
        sendCount++;
        const delay = sendCount === 1 ? 50 : 5; // first send is slower
        await new Promise((r) => setTimeout(r, delay));
        deliveryOrder.push(payload.notificationType);
        return { success: true };
      },
    };

    service.registerAdapter(slowAdapter);

    const orderCreatedEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    const statusChangedEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    // Emit both events in sequence — order_confirmation must be delivered before order_status_update
    await eventBus.emit(orderCreatedEvent);
    await eventBus.emit(statusChangedEvent);

    expect(deliveryOrder).toEqual(['order_confirmation', 'order_status_update']);

    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(2);
    expect(notifications[0]?.notificationType).toBe('order_confirmation');
    expect(notifications[1]?.notificationType).toBe('order_status_update');
  });
});

